import React, { useEffect, useState } from 'react';
import { Menu, Search, Bell, Sun, Moon } from 'lucide-react';
import { cn } from '../utils/cn';
import { Input } from './ui/Input';
import { Button } from './ui/Button';

export function Navbar({ onMenuClick }) {
    const [isDark, setIsDark] = useState(
        document.documentElement.classList.contains('dark') ||
        window.matchMedia('(prefers-color-scheme: dark)').matches
    );

    useEffect(() => {
        if (isDark) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }, [isDark]);

    const toggleTheme = () => setIsDark(!isDark);

    return (
        <header className="sticky top-0 z-30 flex h-16 w-full items-center justify-between border-b border-border bg-background/80 px-4 backdrop-blur-md transition-all shadow-sm">
            <div className="flex items-center gap-4 flex-1">
                <button
                    onClick={onMenuClick}
                    className="lg:hidden p-2 rounded-md hover:bg-accent transition-colors"
                >
                    <Menu size={24} />
                </button>

                <div className="hidden md:block w-full max-w-sm">
                    <Input
                        type="text"
                        placeholder="Search requests..."
                        icon={Search}
                        className="h-10 bg-muted/50 border-none"
                    />
                </div>
            </div>

            <div className="flex items-center gap-3">
                <Button variant="ghost" size="icon" className="rounded-full relative" title="Notifications">
                    <Bell size={20} />
                    <span className="absolute top-2 right-2.5 h-2 w-2 rounded-full bg-destructive border-2 border-background"></span>
                </Button>

                <Button variant="ghost" size="icon" onClick={toggleTheme} className="rounded-full" title="Toggle Theme">
                    {isDark ? <Sun size={20} /> : <Moon size={20} />}
                </Button>

                <div className="ml-2 h-8 w-8 rounded-full bg-gradient-to-tr from-primary to-accent-400 p-[2px] cursor-pointer">
                    <img
                        src="https://api.dicebear.com/7.x/notionists/svg?seed=Felix&backgroundColor=transparent"
                        alt="User avatar"
                        className="h-full w-full rounded-full bg-card object-cover"
                    />
                </div>
            </div>
        </header>
    );
}

import React, { useState, useEffect } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { cn } from '../utils/cn';
import {
    LayoutDashboard,
    List,
    PlusCircle,
    ShieldCheck,
    Settings,
    ChevronLeft,
    ChevronRight,
    LogOut
} from 'lucide-react';
import { Button } from './ui/Button';

const navItems = [
    { name: 'Dashboard', href: '/', icon: LayoutDashboard },
    { name: 'All Requests', href: '/requests', icon: List },
    { name: 'Create Request', href: '/create', icon: PlusCircle },
    { name: 'Admin Panel', href: '/admin', icon: ShieldCheck },
    { name: 'Settings', href: '/settings', icon: Settings },
];

export function Sidebar({ isOpen, setIsOpen, isMobile }) {
    const location = useLocation();

    const handleMobileClick = () => {
        if (isMobile) {
            setIsOpen(false);
        }
    };

    return (
        <>
            {/* Mobile Overlay */}
            {isMobile && isOpen && (
                <div
                    className="fixed inset-0 bg-black/50 z-40 backdrop-blur-sm"
                    onClick={() => setIsOpen(false)}
                />
            )}

            {/* Sidebar container */}
            <aside
                className={cn(
                    "fixed top-0 left-0 z-50 h-screen transition-all duration-300 ease-in-out border-r border-border bg-card shadow-soft flex flex-col",
                    isOpen ? "w-64" : "w-20 -translate-x-full lg:translate-x-0"
                )}
            >
                <div className="flex h-16 items-center justify-between px-4 border-b border-border">
                    <div className="flex items-center gap-3 overflow-hidden">
                        <div className="flex-shrink-0 h-8 w-8 rounded-lg bg-primary flex items-center justify-center text-primary-foreground font-bold text-xl">
                            S
                        </div>
                        {isOpen && <span className="font-semibold text-lg whitespace-nowrap">ServiceTracker</span>}
                    </div>
                    {!isMobile && (
                        <button
                            onClick={() => setIsOpen(!isOpen)}
                            className="p-1 rounded-md hover:bg-accent text-gray-500"
                        >
                            {isOpen ? <ChevronLeft size={20} /> : <ChevronRight size={20} />}
                        </button>
                    )}
                </div>

                <div className="flex-1 py-6 flex flex-col gap-2 px-3 overflow-y-auto overflow-x-hidden">
                    {navItems.map((item) => {
                        const isActive = location.pathname === item.href;
                        return (
                            <NavLink
                                key={item.href}
                                to={item.href}
                                onClick={handleMobileClick}
                                className={cn(
                                    "flex items-center rounded-xl transition-all duration-200 group text-sm font-medium",
                                    isOpen ? "px-3 py-2.5" : "justify-center p-3 text-center",
                                    isActive
                                        ? "bg-primary text-primary-foreground shadow-sm"
                                        : "text-foreground/70 hover:bg-accent hover:text-accent-foreground"
                                )}
                                title={!isOpen ? item.name : undefined}
                            >
                                <item.icon size={20} className={cn("flex-shrink-0", isOpen && "mr-3")} />
                                {isOpen && <span className="whitespace-nowrap">{item.name}</span>}
                            </NavLink>
                        );
                    })}
                </div>

                <div className="p-4 border-t border-border">
                    <NavLink
                        to="/login"
                        className={cn(
                            "flex items-center rounded-xl transition-all duration-200 group text-sm font-medium text-foreground/70 hover:bg-destructive/10 hover:text-destructive",
                            isOpen ? "px-3 py-2.5" : "justify-center p-3 text-center"
                        )}
                        title={!isOpen ? "Logout" : undefined}
                    >
                        <LogOut size={20} className={cn("flex-shrink-0", isOpen && "mr-3")} />
                        {isOpen && <span>Logout</span>}
                    </NavLink>
                </div>
            </aside>
        </>
    );
}

import React from 'react';
import { cn } from '../../utils/cn';
import { motion } from 'framer-motion';

const buttonVariants = {
    default: "bg-primary text-primary-foreground hover:bg-primary/90 shadow-sm",
    destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90 shadow-sm",
    outline: "border border-input bg-background dark:border-slate-700 dark:bg-slate-800 hover:bg-accent hover:text-accent-foreground dark:hover:bg-slate-700",
    secondary: "bg-gray-100 text-gray-900 hover:bg-gray-200 dark:bg-slate-800 dark:text-gray-100 dark:hover:bg-slate-700",
    ghost: "hover:bg-gray-100 dark:hover:bg-slate-800 hover:text-foreground",
    link: "text-primary underline-offset-4 hover:underline",
};

const sizes = {
    default: "h-10 px-4 py-2",
    sm: "h-9 rounded-lg px-3",
    lg: "h-11 rounded-xl px-8",
    icon: "h-10 w-10",
};

export const Button = React.forwardRef(({ className, variant = "default", size = "default", children, ...props }, ref) => {
    return (
        <motion.button
            ref={ref}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            className={cn(
                "inline-flex items-center justify-center whitespace-nowrap rounded-xl text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
                buttonVariants[variant],
                sizes[size],
                className
            )}
            {...props}
        >
            {children}
        </motion.button>
    );
});
Button.displayName = "Button";

import React from 'react';
import { motion } from 'framer-motion';

export function Loader() {
    return (
        <div className="flex items-center justify-center p-4">
            <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                className="h-8 w-8 rounded-full border-4 border-primary/30 border-t-primary"
            />
        </div>
    );
}

export function Skeleton({ className, ...props }) {
    return (
        <div
            className={`animate-pulse rounded-md bg-gray-200 dark:bg-gray-800 ${className}`}
            {...props}
        />
    );
}

import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';

export function Modal({ isOpen, onClose, title, children }) {
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }
        return () => {
            document.body.style.overflow = 'unset';
        };
    }, [isOpen]);

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm"
                    />
                    <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none p-4 w-full h-full">
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0, y: 20 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 20 }}
                            transition={{ type: "spring", duration: 0.5, bounce: 0.3 }}
                            className="pointer-events-auto w-full max-w-lg max-h-[90vh] overflow-y-auto rounded-2xl bg-card p-6 shadow-glass border border-border"
                        >
                            <div className="flex items-center justify-between mb-4 sticky top-0 bg-card z-10">
                                <h2 className="text-xl font-semibold">{title}</h2>
                                <button
                                    onClick={onClose}
                                    className="rounded-full p-1.5 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                                >
                                    <X size={20} />
                                </button>
                            </div>
                            <div className="mt-2">
                                {children}
                            </div>
                        </motion.div>
                    </div>
                </>
            )}
        </AnimatePresence>
    );
}

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { UploadCloud, File, X, Box, Tag, AlignLeft } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from '../Components/ui/Card';
import { Input } from '../Components/ui/Input';
import { Button } from '../Components/ui/Button';

export default function CreateTicket() {
  const [file, setFile] = useState(null);
  const [priority, setPriority] = useState('Medium');

  const priorities = [
    { name: 'Low', color: 'bg-success' },
    { name: 'Medium', color: 'bg-warning' },
    { name: 'High', color: 'bg-orange-500' },
    { name: 'Critical', color: 'bg-destructive' }
  ];

  const handleDragOver = (e) => {
    e.preventDefault();
  };

  const handleDrop = (e) => {
    e.preventDefault();
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Create Request</h1>
        <p className="text-foreground/60 mt-1">Fill out the details below to submit a new service request.</p>
      </div>

      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}>
        <Card className="border-border/50 shadow-soft">
          <CardHeader className="border-b border-border/50 pb-4">
            <CardTitle>Request Details</CardTitle>
            <CardDescription>Provide as much context as possible to help us assist you.</CardDescription>
          </CardHeader>
          <CardContent className="pt-6 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <Input
                label="Request Title"
                placeholder="e.g. Cannot access email server"
                icon={Box}
                className="md:col-span-2"
              />

              <Input
                label="Category"
                placeholder="Software, Hardware, Access..."
                icon={Tag}
              />

              <div className="space-y-2">
                <label className="text-sm font-medium text-primary pl-1">Priority</label>
                <div className="relative">
                  <select
                    value={priority}
                    onChange={(e) => setPriority(e.target.value)}
                    className="flex h-12 w-full appearance-none rounded-xl border border-input dark:border-slate-700 bg-background/50 dark:bg-slate-900/50 px-3 py-2 text-sm ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 transition-all pl-10 cursor-pointer"
                  >
                    {priorities.map(p => (
                      <option key={p.name} value={p.name}>{p.name}</option>
                    ))}
                  </select>
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none">
                    <div className={`h-3 w-3 rounded-full shadow-sm ${priorities.find(p => p.name === priority)?.color}`}></div>
                  </div>
                </div>
              </div>
            </div>

            <div className="relative pt-2">
              <div className="absolute left-3 top-5 text-gray-500 dark:text-gray-400">
                <AlignLeft size={18} />
              </div>
              <textarea
                className="flex w-full rounded-xl border border-input dark:border-slate-700 bg-background/50 dark:bg-slate-900/50 px-3 py-3 text-sm ring-offset-background placeholder:text-gray-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 transition-all pl-10 min-h-[150px] resize-y"
                placeholder="Detailed description of the issue..."
              ></textarea>
            </div>

            <div>
              <label className="text-sm font-medium text-foreground/80 pl-1 mb-2 block">Attachments</label>

              {!file ? (
                <div
                  onDragOver={handleDragOver}
                  onDrop={handleDrop}
                  className="border-2 border-dashed border-border/60 hover:border-primary/50 dark:hover:border-primary/50 rounded-xl p-8 transition-colors flex flex-col items-center justify-center bg-muted/20 hover:bg-muted/40 cursor-pointer"
                  onClick={() => document.getElementById('file-upload').click()}
                >
                  <div className="p-4 rounded-full bg-primary/10 text-primary mb-4 transition-transform hover:scale-110">
                    <UploadCloud size={32} />
                  </div>
                  <p className="text-sm font-medium">Click or drag file to this area to upload</p>
                  <p className="text-xs text-foreground/50 mt-1">Support for a single or bulk upload. Maximum file size 50MB.</p>
                  <input
                    id="file-upload"
                    type="file"
                    className="hidden"
                    onChange={(e) => e.target.files && setFile(e.target.files[0])}
                  />
                </div>
              ) : (
                <motion.div
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  className="flex items-center justify-between p-4 border border-border rounded-xl bg-card shadow-sm"
                >
                  <div className="flex items-center space-x-4">
                    <div className="p-3 bg-primary/10 text-primary rounded-lg">
                      <File size={24} />
                    </div>
                    <div>
                      <p className="text-sm font-medium">{file.name}</p>
                      <p className="text-xs text-foreground/50">{(file.size / 1024).toFixed(1)} KB</p>
                    </div>
                  </div>
                  <button
                    onClick={() => setFile(null)}
                    className="p-2 hover:bg-destructive/10 text-destructive rounded-lg transition-colors"
                  >
                    <X size={20} />
                  </button>
                </motion.div>
              )}
            </div>
          </CardContent>
          <CardFooter className="flex justify-between border-t border-border/50 pt-6">
            <Button variant="outline">Cancel</Button>
            <Button>Submit Request</Button>
          </CardFooter>
        </Card>
      </motion.div>
    </div>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import { Activity, Clock, CheckCircle, AlertCircle, TrendingUp } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '../Components/ui/Card';
import { Badge } from '../Components/ui/Badge';

const stats = [
  { label: 'Total Requests', value: '1,284', icon: Activity, trend: '+12.5%', color: 'text-primary', bg: 'bg-primary/10' },
  { label: 'Pending', value: '42', icon: Clock, trend: '-2.4%', color: 'text-warning', bg: 'bg-warning/10' },
  { label: 'Resolved', value: '1,120', icon: CheckCircle, trend: '+18.2%', color: 'text-success', bg: 'bg-success/10' },
  { label: 'In Progress', value: '122', icon: AlertCircle, trend: '+4.1%', color: 'text-accent-500', bg: 'bg-accent-500/10' },
];

const recentRequests = [
  { id: 'REQ-001', title: 'Server connection timeout', user: 'Alex Mitchell', status: 'In Progress', date: 'Just now', priority: 'High' },
  { id: 'REQ-002', title: 'Update styling on checkout page', user: 'Sarah Jensen', status: 'Pending', date: '2 hrs ago', priority: 'Medium' },
  { id: 'REQ-003', title: 'Database backup failed', user: 'David Kim', status: 'Resolved', date: 'Yesterday', priority: 'Critical' },
  { id: 'REQ-004', title: 'User authentication bug', user: 'Emma Watson', status: 'Pending', date: 'Yesterday', priority: 'High' },
  { id: 'REQ-005', title: 'New onboarding flow UI', user: 'James Smith', status: 'Resolved', date: 'Oct 24', priority: 'Low' },
];

const getStatusBadge = (status) => {
  switch (status) {
    case 'Resolved': return <Badge variant="success">Resolved</Badge>;
    case 'Pending': return <Badge variant="warning">Pending</Badge>;
    case 'In Progress': return <Badge variant="secondary" className="bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-400 border-blue-200 dark:border-blue-800">In Progress</Badge>;
    default: return <Badge>{status}</Badge>;
  }
};

const getPriorityColor = (priority) => {
  switch (priority) {
    case 'Critical': return 'text-destructive';
    case 'High': return 'text-orange-500';
    case 'Medium': return 'text-warning';
    case 'Low': return 'text-success';
    default: return 'text-foreground/70';
  }
};

export default function Dashboard() {
  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Overview</h1>
          <p className="text-foreground/60 mt-1">Here's what's happening with your service requests today.</p>
        </div>
      </div>

      <div className="grid gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-4">
        {stats.map((stat, index) => (
          <motion.div
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: index * 0.1 }}
          >
            <Card className="border-border/50 hover:shadow-soft transition-all duration-300">
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-foreground/60">{stat.label}</p>
                    <h3 className="text-3xl font-bold mt-2">{stat.value}</h3>
                  </div>
                  <div className={`h-12 w-12 rounded-2xl flex items-center justify-center ${stat.bg}`}>
                    <stat.icon className={`h-6 w-6 ${stat.color}`} />
                  </div>
                </div>
                <div className="mt-4 flex items-center text-sm">
                  <TrendingUp className="h-4 w-4 mr-1 text-success" />
                  <span className="text-success font-medium">{stat.trend}</span>
                  <span className="text-foreground/50 ml-2">from last month</span>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        ))}
      </div>

      <div className="grid gap-6 grid-cols-1 lg:grid-cols-7">
        <motion.div
          className="lg:col-span-4"
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
        >
          <Card className="h-full flex flex-col">
            <CardHeader className="border-b border-border/50 pb-4">
              <CardTitle>Recent Requests</CardTitle>
            </CardHeader>
            <CardContent className="flex-1 p-0">
              <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                  <thead className="text-xs text-foreground/50 uppercase bg-muted/30">
                    <tr>
                      <th className="px-6 py-4 font-medium">Ticket</th>
                      <th className="px-6 py-4 font-medium">Status</th>
                      <th className="px-6 py-4 font-medium">Priority</th>
                      <th className="px-6 py-4 font-medium">User</th>
                      <th className="px-6 py-4 font-medium text-right">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border/50">
                    {recentRequests.map((req, i) => (
                      <motion.tr
                        key={req.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.3 + (i * 0.05) }}
                        className="hover:bg-muted/30 transition-colors"
                      >
                        <td className="px-6 py-4">
                          <div className="font-medium text-foreground">{req.title}</div>
                          <div className="text-xs text-foreground/50 mt-1 uppercase tracking-wider">{req.id}</div>
                        </td>
                        <td className="px-6 py-4">{getStatusBadge(req.status)}</td>
                        <td className="px-6 py-4">
                          <span className={`font-medium ${getPriorityColor(req.priority)}`}>{req.priority}</span>
                        </td>
                        <td className="px-6 py-4 text-foreground/70">{req.user}</td>
                        <td className="px-6 py-4 text-right text-foreground/50">{req.date}</td>
                      </motion.tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </motion.div>

        <motion.div
          className="lg:col-span-3"
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.5, delay: 0.3 }}
        >
          <Card className="h-full">
            <CardHeader className="border-b border-border/50 pb-4">
              <CardTitle>Request Distribution</CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              {/* CSS-based animated bar chart */}
              <div className="space-y-6">
                <div>
                  <div className="flex justify-between text-sm mb-2">
                    <span className="font-medium">Software Issues</span>
                    <span className="text-foreground/60">45%</span>
                  </div>
                  <div className="h-3 w-full bg-muted rounded-full overflow-hidden">
                    <motion.div
                      className="h-full bg-primary rounded-full relative"
                      initial={{ width: 0 }}
                      animate={{ width: "45%" }}
                      transition={{ duration: 1, delay: 0.5, ease: "easeOut" }}
                    >
                      <div className="absolute inset-0 bg-white/20 w-full h-full animate-[shimmer_2s_infinite]"></div>
                    </motion.div>
                  </div>
                </div>

                <div>
                  <div className="flex justify-between text-sm mb-2">
                    <span className="font-medium">Hardware Requests</span>
                    <span className="text-foreground/60">28%</span>
                  </div>
                  <div className="h-3 w-full bg-muted rounded-full overflow-hidden">
                    <motion.div
                      className="h-full bg-accent-500 rounded-full"
                      initial={{ width: 0 }}
                      animate={{ width: "28%" }}
                      transition={{ duration: 1, delay: 0.6, ease: "easeOut" }}
                    />
                  </div>
                </div>

                <div>
                  <div className="flex justify-between text-sm mb-2">
                    <span className="font-medium">Access & Permissions</span>
                    <span className="text-foreground/60">17%</span>
                  </div>
                  <div className="h-3 w-full bg-muted rounded-full overflow-hidden">
                    <motion.div
                      className="h-full bg-warning rounded-full"
                      initial={{ width: 0 }}
                      animate={{ width: "17%" }}
                      transition={{ duration: 1, delay: 0.7, ease: "easeOut" }}
                    />
                  </div>
                </div>

                <div>
                  <div className="flex justify-between text-sm mb-2">
                    <span className="font-medium">Other</span>
                    <span className="text-foreground/60">10%</span>
                  </div>
                  <div className="h-3 w-full bg-muted rounded-full overflow-hidden">
                    <motion.div
                      className="h-full bg-slate-400 dark:bg-slate-600 rounded-full"
                      initial={{ width: 0 }}
                      animate={{ width: "10%" }}
                      transition={{ duration: 1, delay: 0.8, ease: "easeOut" }}
                    />
                  </div>
                </div>
              </div>

              {/* Pie chart representation via conic gradient */}
              <div className="mt-8 pt-8 border-t border-border/50 flex flex-col items-center">
                <h4 className="text-sm font-medium mb-6 self-start">Priority Breakdown</h4>
                <div className="relative w-40 h-40">
                  <motion.div
                    initial={{ scale: 0, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ type: "spring", delay: 1 }}
                    style={{
                      background: `conic-gradient(var(--destructive) 0% 15%, var(--warning) 15% 45%, var(--primary) 45% 80%, var(--success) 80% 100%)`
                    }}
                    className="w-full h-full rounded-full shadow-soft opacity-90"
                  />
                  {/* Donut hole for modern look */}
                  <div className="absolute inset-2 rounded-full bg-card shadow-inner flex items-center justify-center">
                    <div className="text-center">
                      <div className="text-2xl font-bold">100%</div>
                      <div className="text-[10px] text-foreground/50 uppercase tracking-widest">Total</div>
                    </div>
                  </div>
                </div>
                <div className="flex flex-wrap gap-4 mt-6 justify-center text-xs">
                  <div className="flex items-center"><div className="w-3 h-3 rounded-full bg-destructive mr-2"></div> Critical</div>
                  <div className="flex items-center"><div className="w-3 h-3 rounded-full bg-warning mr-2"></div> High</div>
                  <div className="flex items-center"><div className="w-3 h-3 rounded-full bg-primary mr-2"></div> Medium</div>
                  <div className="flex items-center"><div className="w-3 h-3 rounded-full bg-success mr-2"></div> Low</div>
                </div>
              </div>
            </CardContent>
          </Card>
        </motion.div>
      </div>
    </div>
  );
}

